insert into aura_exercise_catalog (id, payload, updated_at) values
  ('E57E6201-E916-5460-BFB1-A6758758E3EC'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"E57E6201-E916-5460-BFB1-A6758758E3EC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders","Rhomboids"],"name":"Dumbbell Decline Shrug V. 2","notes":"","plannedSets":3,"proTips":["Set up a decline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting on it.","Hold a dumbbell in each hand with your palms facing each other and your arms fully extended.","Keeping your arms straight, raise your shoulders as high as possible while squeezing your shoulder blades together.","Hold the contraction for a brief pause, then lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6997E58F-4095-557A-85A4-3FF99597BDF4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4DFD8487-0622-5781-A41D-CD3268573E67'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"4DFD8487-0622-5781-A41D-CD3268573E67","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Decline Triceps Extension","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your head lower than your feet and hold a dumbbell in each hand, palms facing each other.","Extend your arms fully, keeping your elbows close to your head.","Lower the dumbbells slowly behind your head, bending your elbows.","Pause for a moment, then raise the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2FE7EAEF-C13D-5EC8-B951-F9B2A8691BB3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BFE33FB6-9C21-54BA-97A0-0EDF36313BF6'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BFE33FB6-9C21-54BA-97A0-0EDF36313BF6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Decline Twist Fly","notes":"","plannedSets":3,"proTips":["Lie down on a decline bench with your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended straight up over your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","As you lower the dumbbells, twist your wrists so that your palms face forward at the bottom of the movement.","Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles at the top.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"232F10DB-1807-5D67-9C5C-4A1247062A3E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9145FBB3-B856-56D5-8F58-9C188BADA710'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9145FBB3-B856-56D5-8F58-9C188BADA710","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Wrist Flexors","Wrist Extensors"],"name":"Dumbbell Finger Curls","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh, palm facing up.","Allow the dumbbell to roll down to your fingertips, then curl it back up by flexing your fingers.","Repeat for the desired number of repetitions, then switch to the other hand."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B274FBF6-2182-59A7-9E26-EC5833BEDFD6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7D5067B0-0327-555E-8105-3ECEA6F7F190'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7D5067B0-0327-555E-8105-3ECEA6F7F190","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders"],"name":"Dumbbell Fly","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, with a slight bend in your elbows.","Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6B221FBC-575C-50D1-BA3E-538E75870569","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FD84E340-B541-542E-AF10-D9591DD5CC2C'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"FD84E340-B541-542E-AF10-D9591DD5CC2C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Fly On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball and hold a dumbbell in each hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported by the ball.","Extend your arms straight up above your chest, palms facing each other.","Bend your elbows slightly and lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and squeeze your chest muscles as you bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7C90C700-F406-55C2-AA83-1F3524F444A2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0722DECA-4E07-5BEF-AD88-9934E4C75B2A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"0722DECA-4E07-5BEF-AD88-9934E4C75B2A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Core"],"name":"Dumbbell Forward Lunge Triceps Extension","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","Keep your back straight and your chest up.","Extend your arms straight overhead, keeping your elbows close to your ears.","Lower the dumbbells behind your head by bending your elbows.","Pause for a moment, then straighten your arms to return to the starting position.","Repeat the movement for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A4ABC411-D344-506B-B17F-6F1852D1C45E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2E92C95E-3112-5FDB-AF2D-E8EDB9211E02'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2E92C95E-3112-5FDB-AF2D-E8EDB9211E02","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Biceps","Trapezius"],"name":"Dumbbell Front Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"29C26E81-7F64-5B4D-A09F-F9608C6E0E11","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('45B25E48-3B6F-5F42-B8BB-B0A6195FDADD'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"45B25E48-3B6F-5F42-B8BB-B0A6195FDADD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Biceps"],"name":"Dumbbell Front Raise V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keep your back straight and engage your core.","Slowly lift the dumbbells in front of you, with your arms straight, until they are at shoulder level.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FFA43524-A0B1-5AC6-9C6A-D01AF24B8B4F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8F98C598-7309-5987-93A9-7074DA7D19E5'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"8F98C598-7309-5987-93A9-7074DA7D19E5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rotator Cuff"],"name":"Dumbbell Full Can Lateral Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"640B8D82-26C0-5EAE-BA0E-C157D6F994C9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('600CD028-FB67-58FE-B318-C41D54C2C94D'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"600CD028-FB67-58FE-B318-C41D54C2C94D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Dumbbell Goblet Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands.","Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A5B013D7-E9CF-59E5-B322-11CD2171DC1E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('32280A2F-1936-5712-B130-01641D797F77'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"32280A2F-1936-5712-B130-01641D797F77","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Hammer Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5AACCD6E-3377-5FAB-82DE-8BA90C1ECCAB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F08315A4-268E-5EE1-A201-9D5451B66ABF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F08315A4-268E-5EE1-A201-9D5451B66ABF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Hammer Curl On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F18B2C58-326F-56EE-8DC8-A0A9CC501A8B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4E55B86F-D9DD-513F-9197-38CF1D6EBA7B'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"4E55B86F-D9DD-513F-9197-38CF1D6EBA7B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Hammer Curl V. 2","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"58DFD8C4-8566-5C49-ACCE-BF4EAF452690","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7E4ECF2F-2319-535A-9E24-D31655BE195C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7E4ECF2F-2319-535A-9E24-D31655BE195C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Hammer Curls (With Arm Blaster)","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, while holding your upper arm stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8621CCD0-65D6-5928-8ACE-552F83B4154A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('77AE3630-C85B-5806-A2BC-F23E2ED23396'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"77AE3630-C85B-5806-A2BC-F23E2ED23396","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell High Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your upper arms stationary and curl the dumbbells as high as possible while contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BEECEDD6-ED6E-5C1F-90C7-B7998466E29D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C8E0DA8F-3B3E-527A-BD3C-6B7F0EC461CC'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"C8E0DA8F-3B3E-527A-BD3C-6B7F0EC461CC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline Alternate Press","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Lean back on the bench and use your thighs to help raise the dumbbells to shoulder height, palms facing forward.","Once at shoulder height, rotate your wrists so that the palms of your hands are facing forward.","Push the dumbbells up with your chest and shoulders, extending your arms fully.","Lower the dumbbells back down to the starting position, keeping your elbows slightly bent.","Repeat for the desired number of repetitions, alternating arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8EACC721-061A-59D6-B307-0BC3361A8A50","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9B9A846A-FF10-542E-8E52-56DA0F485AD9'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9B9A846A-FF10-542E-8E52-56DA0F485AD9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline Bench Press","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench.","Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height.","Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.","Push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FC77D235-EBF4-59E8-BC79-A2F3463493A0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('404DB2F4-BAE4-5DB2-BA17-4F86A0885AFA'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"404DB2F4-BAE4-5DB2-BA17-4F86A0885AFA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Incline Biceps Curl","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E9422E66-B563-5F83-8F94-49305F869EFF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E199BECD-DA09-5934-8F2D-B1A1375E19B1'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"E199BECD-DA09-5934-8F2D-B1A1375E19B1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline Breeding","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing forward.","Start with your arms fully extended, perpendicular to the ground.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F5DEE83E-180A-521F-A82C-A47E92AA02CB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ABD8168D-1CBE-5A6A-A735-2A5799C974F4'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"ABD8168D-1CBE-5A6A-A735-2A5799C974F4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Incline Curl","notes":"","plannedSets":3,"proTips":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing forward.","Rest your upper arms on the incline bench and let your elbows hang down, fully extending your arms.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"262E33DF-F92C-5BAB-8EBF-C5E1980CDFE4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2F445B2F-F0C7-56B8-B18E-9EF6214880FC'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2F445B2F-F0C7-56B8-B18E-9EF6214880FC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Incline Curl V. 2","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CE98A3AA-498C-5C33-8E24-B15DD700F59E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AC075005-EE73-5FF0-977B-9CDDC3D3829D'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"AC075005-EE73-5FF0-977B-9CDDC3D3829D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders"],"name":"Dumbbell Incline Fly","notes":"","plannedSets":3,"proTips":["Set an incline bench to a 45-degree angle.","Sit on the bench with a dumbbell in each hand, palms facing each other.","Lie back on the bench and press the dumbbells up to the starting position, directly above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0FFB36BC-9516-5BB9-AEC4-098325AF7916","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1C02C74E-61D2-5B88-B4CF-A235EE7519B1'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1C02C74E-61D2-5B88-B4CF-A235EE7519B1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders"],"name":"Dumbbell Incline Fly On Exercise Ball","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on an exercise ball and roll forward until your upper back is resting on the incline bench.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DA1D7075-5849-5EBA-B63B-5F41D3A7F7FC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('648B67F5-42E7-5772-9D70-7473629B75F3'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"648B67F5-42E7-5772-9D70-7473629B75F3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Incline Hammer Curl","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in each hand, palms facing your torso and arms fully extended.","Keep your back against the bench and your feet flat on the floor.","While keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"094DA19E-D826-5ED7-AEF7-AE7C33A1C371","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B216AB6D-B90C-5274-814F-F0E117A0564A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B216AB6D-B90C-5274-814F-F0E117A0564A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline Hammer Press","notes":"","plannedSets":3,"proTips":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, resting on your thighs.","Lie back on the bench and position the dumbbells at shoulder level with your palms facing each other.","Press the dumbbells up and away from your body until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A67F5204-4118-56DB-AF15-C2F41541DD96","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7CE3C7BE-4AE0-5510-BE8F-0CC45B501EFC'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7CE3C7BE-4AE0-5510-BE8F-0CC45B501EFC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Dumbbell Incline Hammer Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with a dumbbell in each hand, palms facing each other.","Walk your feet forward and roll your body down the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.","Press the dumbbells up and slightly inward, keeping your palms facing each other.","Extend your arms fully, squeezing your triceps at the top of the movement.","Slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E2AD17F8-F791-5CAB-9A12-B5D271A3135A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7BFC4747-5A4F-5842-8F0A-E104D011BF7E'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7BFC4747-5A4F-5842-8F0A-E104D011BF7E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Incline Inner Biceps Curl","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in each hand, palms facing each other.","Rest your upper arms on the bench, allowing your elbows to hang down and your palms to face forward.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C7A5AAB3-158A-5F93-90C1-815058DE13DB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('05362280-FDAF-50BF-858F-4E08AE40A05D'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"05362280-FDAF-50BF-858F-4E08AE40A05D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Dumbbell Incline One Arm Fly","notes":"","plannedSets":3,"proTips":["Adjust the incline bench to a 30-45 degree angle.","Sit on the bench with a dumbbell in one hand, resting it on your thigh.","Lie back on the bench, keeping your feet flat on the ground.","Hold the dumbbell with your arm extended straight up over your chest.","Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.","Pause when your arm is parallel to the ground, then reverse the motion to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6D32B740-41D4-530E-A142-29F77D87F474","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('06CE21F9-8394-5D8B-9DFD-654DF4D6484A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"06CE21F9-8394-5D8B-9DFD-654DF4D6484A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders"],"name":"Dumbbell Incline One Arm Fly On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with a dumbbell in one hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with your arm extended straight up over your chest, palm facing inwards.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment when your arm is parallel to the ground.","Engage your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EE30D84C-AC89-541F-A565-3E0E38F77128","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('485DE48B-7F10-51C9-BBED-1E59DC6D5638'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"485DE48B-7F10-51C9-BBED-1E59DC6D5638","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Chest"],"name":"Dumbbell Incline One Arm Hammer Press","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in one hand, resting on your thigh.","Lean back on the bench and use your thigh to help raise the dumbbell to shoulder height.","Rotate your wrist so that your palm is facing inward, towards your body.","Press the dumbbell up and away from your body, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"930FF248-BB09-533A-A264-542BC89E713F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9B5C0AA3-3DCA-5C37-9D4C-E9288BB92E99'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9B5C0AA3-3DCA-5C37-9D4C-E9288BB92E99","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Chest"],"name":"Dumbbell Incline One Arm Hammer Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with a dumbbell in one hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with your palm facing inward and your elbow bent at a 90-degree angle.","Press the dumbbell up towards the ceiling, straightening your arm.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"10A4DF9B-2EFD-5B60-B611-9BA5C947B4DF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('322298EA-E050-5B14-BD40-3A8CB73C7020'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"322298EA-E050-5B14-BD40-3A8CB73C7020","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Triceps"],"name":"Dumbbell Incline One Arm Lateral Raise","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in one hand, resting it on your thigh.","Lean forward and position your upper arm against the inside of your thigh.","Raise the dumbbell to the side, keeping your arm slightly bent and your palm facing down.","Continue lifting until your arm is parallel to the floor.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"460CA4D6-5706-527C-B4BF-972DAC736C6F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('03F07558-0869-59A5-89E9-075084F860FB'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"03F07558-0869-59A5-89E9-075084F860FB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline One Arm Press","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in one hand, resting on your thigh.","Lie back on the bench and position the dumbbell at shoulder level, palm facing forward.","Press the dumbbell upward and slightly inward, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C23F88A0-525D-542D-ADA9-7A60DAF815FD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0D208F8B-B5D9-58AA-9B66-5AC95900F5DA'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"0D208F8B-B5D9-58AA-9B66-5AC95900F5DA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline One Arm Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground.","Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbell at shoulder height with your palm facing forward.","Press the dumbbell upward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2CC27787-ACA7-540A-9E56-323B65E4F23B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('511984AA-B114-552A-8E20-3ABA9D7C1454'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"511984AA-B114-552A-8E20-3ABA9D7C1454","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline Palm-In Press","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench with a dumbbell in each hand, palms facing each other.","Plant your feet firmly on the ground and keep your back straight against the bench.","Start with the dumbbells at shoulder level, elbows bent and palms facing each other.","Press the dumbbells up and away from your body, extending your arms fully.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"81D9F801-EAE1-536D-81B3-9FC86E0B6747","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3E98445B-3D44-545C-9403-DD066A709986'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3E98445B-3D44-545C-9403-DD066A709986","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with a dumbbell in each hand, palms facing forward.","Slowly walk your feet forward, rolling your body down the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.","Press the dumbbells upward, extending your arms fully.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EF590AB7-3DB7-57FD-AAFD-C4FE3C3F32AE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BC8740FA-3D67-537A-992C-56A2706A0718'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BC8740FA-3D67-537A-992C-56A2706A0718","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Triceps"],"name":"Dumbbell Incline Raise","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Lean back on the bench and raise the dumbbells to shoulder height, palms facing forward.","Keeping your back against the bench, exhale and raise the dumbbells above your head, fully extending your arms.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"076BCCB5-47BF-5C7F-9970-453B3DC75A99","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('41A301FA-51EB-5019-AE28-56626F78362E'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"41A301FA-51EB-5019-AE28-56626F78362E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Dumbbell Incline Rear Lateral Raise","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your chest against the backrest and hold a dumbbell in each hand.","Extend your arms straight down with your palms facing each other.","Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"58514EE4-14A3-5D2E-B156-AA7A36656A38","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('51208EA6-4B2B-5C15-81BB-AD314A7D4593'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"51208EA6-4B2B-5C15-81BB-AD314A7D4593","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Dumbbell Incline Row","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Grab a dumbbell in each hand and sit on the bench with your chest against the incline.","Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DEFE78D4-B8A2-5CE6-A386-37A0D57C06E7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9ABC835D-BE67-5336-9869-7B92A4F97715'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9ABC835D-BE67-5336-9869-7B92A4F97715","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Serratus Anterior","Deltoids","Trapezius"],"name":"Dumbbell Incline Shoulder Raise","notes":"","plannedSets":3,"proTips":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing down.","Rest the dumbbells on your thighs and lean back onto the bench.","Use your thighs to help raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing forward.","Exhale and slowly raise the dumbbells above your head, keeping a slight bend in your elbows.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1DC4B8FB-34B1-5F2F-90A8-18F1F4000E3E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9D59EBF0-4866-5EC2-B0AD-88663F5ED5DC'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9D59EBF0-4866-5EC2-B0AD-88663F5ED5DC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders"],"name":"Dumbbell Incline Shrug","notes":"","plannedSets":3,"proTips":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand.","Place your feet flat on the ground and let your arms hang straight down with your palms facing your body.","Keeping your arms straight, shrug your shoulders up towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C31175D5-A3DC-5759-BF34-DC7D2DA8AC51","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BC8C035C-0A6F-5A61-8AE1-8CB95A0CDB52'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BC8C035C-0A6F-5A61-8AE1-8CB95A0CDB52","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Dumbbell Incline T-Raise","notes":"","plannedSets":3,"proTips":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.","Lean forward and let your arms hang straight down, perpendicular to the floor.","Keeping your arms straight, raise them out to the sides until they are parallel to the floor, forming a ''T'' shape with your body.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0F734A24-3681-5280-B595-147B63F456AE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6265A3ED-BA01-5CA2-B32E-5228AA3D454A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6265A3ED-BA01-5CA2-B32E-5228AA3D454A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Incline Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in each hand, palms facing inwards.","Extend your arms fully overhead, keeping your elbows close to your head.","Lower the dumbbells behind your head by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then raise the dumbbells back to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"67E4BE53-7B41-5296-BDAE-EFDABCD8E003","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B7E30F75-5779-55CC-B500-00B244FA2C9A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B7E30F75-5779-55CC-B500-00B244FA2C9A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Incline Twisted Flyes","notes":"","plannedSets":3,"proTips":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing each other.","Lie back on the bench and press the dumbbells up to the starting position, directly above your chest, with your arms extended.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","As you lower the dumbbells, rotate your wrists so that your palms face forward at the bottom of the movement.","Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles together at the top.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CC027237-A34B-51B2-A0DE-5877279CC783","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('690C4E07-8196-56F1-98AB-10079D87809C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"690C4E07-8196-56F1-98AB-10079D87809C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Incline Two Arm Extension","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Slowly lie back on the bench, keeping the dumbbells close to your chest.","Once you are fully lying down, extend your arms straight up towards the ceiling, keeping your elbows slightly bent.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"96AC9516-B7B3-5B4D-B0A7-CABD37FEA704","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D419D796-6D00-5A82-9824-7093F9473630'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"D419D796-6D00-5A82-9824-7093F9473630","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders","Rear Deltoids"],"name":"Dumbbell Incline Y-Raise","notes":"","plannedSets":3,"proTips":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.","Lean forward slightly and let your arms hang straight down, keeping a slight bend in your elbows.","Raise your arms out to the sides and up in a Y shape until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D3920725-A5D4-50D8-BEA4-D7DCB4B62B9C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('703680E9-275E-50EF-9960-30F46C05D878'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"703680E9-275E-50EF-9960-30F46C05D878","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"Dumbbell Iron Cross","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body.","Pause for a moment, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EE547D81-6766-5DD2-A239-12E23792BB72","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8081C987-1927-53CC-BC42-AFB766F3CD4B'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"8081C987-1927-53CC-BC42-AFB766F3CD4B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Kickback","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2A423ADE-1F13-515B-A255-D2C31B2F0E3D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6E7B1493-A29E-5F35-B539-4CE2A969BFFC'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6E7B1493-A29E-5F35-B539-4CE2A969BFFC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Back"],"name":"Dumbbell Kickbacks On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing inwards and your arms bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1D1DD1BF-B390-55AD-ACDC-DFA89D5AC522","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B5D36011-B81F-5F07-99D9-81A3BC941295'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B5D36011-B81F-5F07-99D9-81A3BC941295","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Kneeling Bicep Curl Exercise Ball","notes":"","plannedSets":3,"proTips":["Kneel on the floor with an exercise ball in front of you.","Place your elbows on top of the exercise ball, holding a dumbbell in each hand with your palms facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B5C5A419-DBE8-5CF3-A9BB-B230B82B71F9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7EF0DC4E-2468-5C83-A977-1B571159228A'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7EF0DC4E-2468-5C83-A977-1B571159228A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps"],"name":"Dumbbell Lateral Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D424C903-DBFF-50EA-9E7C-E58D7EAD6835","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F8068143-2EFA-5D6B-A070-DF25CAC22CBB'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F8068143-2EFA-5D6B-A070-DF25CAC22CBB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Biceps"],"name":"Dumbbell Lateral To Front Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the ground, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Next, raise your arms in front of you until they are parallel to the ground, again keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"71310F3D-6651-5C72-BEA6-D84E784C7197","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9691765F-B527-57B1-8812-0BF5C0298C32'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9691765F-B527-57B1-8812-0BF5C0298C32","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Dumbbell Lunge","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","Keep your back straight and your chest up as you lower your body.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Alternate legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E5F78542-A425-52E4-B9E3-BF439D2CA79E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CDFE1081-A28D-5085-98F9-F6CD32163FB9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"CDFE1081-A28D-5085-98F9-F6CD32163FB9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Quadriceps","Hamstrings"],"name":"Dumbbell Lunge With Bicep Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground.","As you lunge forward, simultaneously curl the dumbbells towards your shoulders, keeping your elbows close to your body.","Pause for a moment at the bottom of the lunge, then push through your right heel to return to the starting position, lowering the dumbbells back down to your sides.","Repeat the lunge and bicep curl on the opposite side, stepping forward with your left foot.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BA39CB62-8657-561A-8181-F976C54523F4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('85C2022A-A8DC-551A-AED0-B4A4C8CAA190'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"85C2022A-A8DC-551A-AED0-B4A4C8CAA190","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Lying Alternate Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower one dumbbell down towards your head, bending at the elbow, while keeping the other arm extended.","Pause for a moment at the bottom, then raise the dumbbell back up to the starting position.","Repeat with the other arm, alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"163B28C9-8BFA-5F67-944B-EF85CDFBBD0E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3EEC1FFD-0D85-56F9-BDDD-2CB5FB1F40A0'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3EEC1FFD-0D85-56F9-BDDD-2CB5FB1F40A0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Dumbbell Lying Elbow Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up over your chest.","Lower the dumbbells towards your shoulders by bending your elbows, keeping your upper arms stationary.","Pause for a moment at the bottom, then press the dumbbells back up to the starting position by extending your elbows.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3143CCFC-7503-5706-8CB7-A39E37AB1AAB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A1C1E140-609D-573A-AF70-0566FA3739E7'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"A1C1E140-609D-573A-AF70-0566FA3739E7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Lying Extension (Across Face)","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold a dumbbell with both hands and extend your arms straight up above your chest, palms facing each other.","Keeping your upper arms stationary, slowly lower the dumbbell in an arc behind your head until your forearms are parallel to the ground.","Pause for a moment, then contract your triceps to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6DE494DB-E990-5005-8059-31B434ECA351","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7800D8FD-BB56-5EF6-BC3F-4F18D9CDE8CC'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7800D8FD-BB56-5EF6-BC3F-4F18D9CDE8CC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Rotator Cuff","Triceps"],"name":"Dumbbell Lying External Shoulder Rotation","notes":"","plannedSets":3,"proTips":["Lie on your side on a flat bench with your upper arm against your side and your elbow bent 90 degrees.","Hold a dumbbell in your hand with your palm facing down.","Keeping your upper arm against your side, slowly rotate your forearm upward as far as possible.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"D0BF7A28-E4D2-5AD8-A79F-A762C5ACEB25","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('B0A5EF34-424A-5764-B525-65F9FC0FF9AB'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B0A5EF34-424A-5764-B525-65F9FC0FF9AB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes"],"name":"Dumbbell Lying Femoral","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and a dumbbell resting on your lower abdomen.","Bend your knees and bring the dumbbell towards your glutes, keeping your feet flat on the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3FD285C6-9C18-5159-B5AC-130C0E8F6246","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E9F0F905-9152-52C5-A2BC-EAF7BB690825'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"E9F0F905-9152-52C5-A2BC-EAF7BB690825","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell Lying Hammer Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up.","Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.","Press the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"270232FB-FFA9-5BB3-AF03-C211E5FE63FB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('11ADEBC1-0A1C-52B7-82AA-A68C532C1F04'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"11ADEBC1-0A1C-52B7-82AA-A68C532C1F04","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Lying On Floor Rear Delt Raise","notes":"","plannedSets":3,"proTips":["Lie face down on the floor with a dumbbell in each hand, palms facing each other.","Extend your arms straight out in front of you, keeping a slight bend in your elbows.","Engaging your shoulder muscles, lift your arms up and out to the sides, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4486988E-6A5D-5B5B-B73E-395BDD238612","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1BB5A378-358B-5659-A504-02C71C0E7FFF'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1BB5A378-358B-5659-A504-02C71C0E7FFF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Lying One Arm Deltoid Rear","notes":"","plannedSets":3,"proTips":["Lie face down on a flat bench with a dumbbell in one hand, palm facing inwards.","Extend your arm straight down towards the floor, keeping it close to your body.","Raise your arm up and back, squeezing your shoulder blade towards your spine.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EF8CF10E-3F90-5CC3-AD5C-FA79D948E915","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AC15E390-DE80-5962-90ED-879EE2E6241D'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"AC15E390-DE80-5962-90ED-879EE2E6241D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell Lying One Arm Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in one hand and your feet flat on the ground.","Hold the dumbbell at shoulder level with your palm facing forward.","Press the dumbbell upward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"564FF6CD-19BD-50F0-A6C0-2DDB8AFF0538","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AE2D2C15-D5A3-5164-817D-1471ECF1EEA5'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"AE2D2C15-D5A3-5164-817D-1471ECF1EEA5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell Lying One Arm Press V. 2","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your back supported and feet flat on the ground.","Hold a dumbbell in one hand with your palm facing towards your feet.","Extend your arm straight up towards the ceiling, keeping your elbow slightly bent.","Slowly lower the dumbbell down towards your chest, keeping your elbow close to your body.","Pause for a moment at the bottom, then push the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"081A965F-E1D3-5652-97D7-90BE19AD2F24","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('577D63B0-5A80-5A16-81A7-ED3C70F1DF89'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"577D63B0-5A80-5A16-81A7-ED3C70F1DF89","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Lying One Arm Pronated Triceps Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in one hand with your palm facing down, and extend your arm straight up above your shoulder.","Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"38B6F61F-808A-554F-B362-954965C2B5CD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6904612E-93AA-5293-9AD0-2CFF1BC02277'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6904612E-93AA-5293-9AD0-2CFF1BC02277","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Dumbbell Lying One Arm Rear Lateral Raise","notes":"","plannedSets":3,"proTips":["Lie face down on a flat bench with a dumbbell in one hand, hanging towards the floor.","Keep your arm straight and lift the dumbbell out to the side, away from your body.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"67EF7D36-A6FA-5A6C-AC4D-A3C43B8177A2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D64D4110-B841-50EF-AEE2-C752157DE18F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"D64D4110-B841-50EF-AEE2-C752157DE18F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Dumbbell Lying One Arm Supinated Triceps Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in one hand with an underhand grip, and extend your arm straight up above your shoulder.","Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EE8D73D0-3FF6-54BA-B757-0910C2A4C912","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0CF44B45-27D0-510E-A8DB-9146904C8136'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"0CF44B45-27D0-510E-A8DB-9146904C8136","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Shoulders"],"name":"Dumbbell Lying Pronation","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your chest facing down and your arms extended straight down, holding a dumbbell in each hand.","Rotate your palms so they are facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells as you rotate your palms to face down.","Inhale and slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EF960189-A9F6-5459-8E4D-5869AECDBB54","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FAE3B361-F234-5D8B-8EE8-D9E447F4870F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"FAE3B361-F234-5D8B-8EE8-D9E447F4870F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Triceps"],"name":"Dumbbell Lying Pronation On Floor","notes":"","plannedSets":3,"proTips":["Lie flat on the floor with your face down and your arms extended straight out in front of you, holding a dumbbell in each hand.","Rotate your palms so they are facing down towards the floor.","Keeping your arms straight, lift the dumbbells off the floor by contracting your forearms.","Continue lifting until your forearms are fully contracted and the dumbbells are at shoulder level.","Hold for a moment, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C8B47251-703D-582B-B218-75BBC23EA2BE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7C71160D-D6CD-5322-875E-DE380ED446F6'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7C71160D-D6CD-5322-875E-DE380ED446F6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Back"],"name":"Dumbbell Lying Pullover On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball and roll forward until your upper back is resting on the ball.","Hold a dumbbell with both hands and extend your arms straight up over your chest.","Slowly lower the dumbbell behind your head while keeping your arms straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3C5ED147-C231-58D2-A7C1-5EC3A5B8D262","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('14D52A26-BA47-5CD4-AD91-E5897B216025'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"14D52A26-BA47-5CD4-AD91-E5897B216025","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders","Biceps"],"name":"Dumbbell Lying Rear Delt Row","notes":"","plannedSets":3,"proTips":["Lie face down on a flat bench with a dumbbell in each hand, palms facing inwards.","Extend your arms straight down towards the floor, keeping a slight bend in your elbows.","Engaging your back muscles, lift the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"BD0A26AC-1DC0-5245-A19C-1C7157D61D42","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D75EF7B3-9F2B-554B-8EDD-7620821A2473'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"D75EF7B3-9F2B-554B-8EDD-7620821A2473","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Dumbbell Lying Rear Lateral Raise","notes":"","plannedSets":3,"proTips":["Lie face down on a flat bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight down towards the floor, keeping a slight bend in your elbows.","Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6A0EE781-775A-51F4-BD70-CB7500176A2E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3807FA1A-AA97-5A15-9461-F5D2DEFA6046'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3807FA1A-AA97-5A15-9461-F5D2DEFA6046","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Lying Single Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest.","Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary.","Pause briefly at the bottom of the movement, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F52AC5E5-1140-5848-B14E-9ADC2C2DE54C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3ABDDEC2-3308-5F38-9E3E-EB9A85175427'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3ABDDEC2-3308-5F38-9E3E-EB9A85175427","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Shoulders"],"name":"Dumbbell Lying Supination","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, curl the dumbbells towards your shoulders by contracting your forearms.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C4A0B3CC-9810-5AD8-B585-DA46A04EDD56","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5E59AF3E-46BC-5FB5-80E4-D738100E3B09'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"5E59AF3E-46BC-5FB5-80E4-D738100E3B09","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Shoulders"],"name":"Dumbbell Lying Supination On Floor","notes":"","plannedSets":3,"proTips":["Lie flat on your back on the floor with your legs extended and your arms by your sides, holding a dumbbell in each hand.","Rotate your palms to face up, keeping your elbows close to your sides.","Slowly curl the dumbbells towards your shoulders, squeezing your forearms.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AA5DAE6B-77EE-5BCB-8BCA-0FF826C6B86A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5164DF86-8B7F-56EB-91FC-646554814B8E'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"5164DF86-8B7F-56EB-91FC-646554814B8E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Lying Supine Biceps Curl","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EA7B9A62-5F7C-5760-9E49-397B9FD15C72","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4BA15168-08A5-51FC-90D8-5F23A3156554'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"4BA15168-08A5-51FC-90D8-5F23A3156554","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Lying Supine Curl","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5FDDDE88-DFE1-50DF-9B1B-E0AF5C41C561","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('03AFB6C3-90A3-5F3B-A9F6-6B016646EB36'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"03AFB6C3-90A3-5F3B-A9F6-6B016646EB36","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Lying Triceps Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, keeping your elbows close to your body.","Lower the dumbbells down towards your forehead, bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"55DA3D6E-19F9-5F57-AA27-D8EF7D3F2EE5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('797AF9E4-1DF2-564A-8E64-789EBB7D5068'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"797AF9E4-1DF2-564A-8E64-789EBB7D5068","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Lying Wide Curl","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1FD5923F-30E1-581A-987F-ACBEDCDCE967","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2A912A71-C3CF-59AD-938A-1A0FC5279BA7'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2A912A71-C3CF-59AD-938A-1A0FC5279BA7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Dumbbell Neutral Grip Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand with a neutral grip (palms facing each other) and your arms extended straight up over your chest.","Slowly lower the dumbbells down towards your chest, keeping your elbows close to your body.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4A13729B-2C8B-5907-8C02-CBD68162B71D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7F067B84-613B-52CF-A325-9F2F56D1FEB8'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7F067B84-613B-52CF-A325-9F2F56D1FEB8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders"],"name":"Dumbbell One Arm Bench Fly","notes":"","plannedSets":3,"proTips":["Sit on a flat bench with a dumbbell in one hand, resting it on top of your thigh.","Lie back on the bench, keeping the dumbbell pressed against your thigh.","Using your free hand, help lift the dumbbell up to the starting position.","Hold the dumbbell directly above your shoulder with your arm extended and palm facing inward.","Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.","Pause when your arm is parallel to the ground, then reverse the movement and bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"682F1FDB-F26A-5173-BFD8-C72D3C57CC1A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BB38C8F6-94CA-556C-AE08-E3BFFDF9B88E'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BB38C8F6-94CA-556C-AE08-E3BFFDF9B88E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Dumbbell One Arm Bent-Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.","Let the dumbbell hang straight down towards the floor, with your arm fully extended.","Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C434E3E1-0A11-5676-A27D-22F0C2DEE7AF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('35E50844-6611-532B-917C-0EEBA219F41A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"35E50844-6611-532B-917C-0EEBA219F41A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell One Arm Chest Fly On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground.","Walk your feet forward, rolling the ball until your upper back is supported on the ball and your head, neck, and shoulders are off the ball.","Extend your arm with the dumbbell straight up above your chest, palm facing inward.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment when your arm is parallel to the ground.","Engage your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0207E7D8-C288-5951-BD98-CB3381721461","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('141C73BF-F968-5A7D-AB96-DB6F8C12F02B'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"141C73BF-F968-5A7D-AB96-DB6F8C12F02B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Concentration Curl (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in one hand with your palm facing up and your arm extended down towards the floor.","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder while contracting your biceps.","Pause for a moment at the top of the movement, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D851FC91-E8F7-57B2-8190-3C036FCDD3DA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DBBA7BF8-4BB3-5AC1-A282-63F6037BA608'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"DBBA7BF8-4BB3-5AC1-A282-63F6037BA608","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell One Arm Decline Chest Press","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with a dumbbell in one hand, resting on your chest.","Place your feet flat on the ground and keep your back pressed against the bench.","Extend your arm and push the dumbbell up towards the ceiling, fully extending your elbow.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FBF960C0-3B4D-5845-9E9C-C6FC0698D1F1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CF673B27-D458-5388-930D-C2B3D8733916'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"CF673B27-D458-5388-930D-C2B3D8733916","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell One Arm Fly On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground.","Walk your feet forward and roll your body down until your upper back is resting on the exercise ball.","Extend your arm with the dumbbell straight up above your chest, palm facing inwards.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment, then squeeze your chest muscles to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"948E7278-5919-5A1C-9F90-DE45F034E81A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6B82980C-2E2F-5A58-A68F-83CBE1818553'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6B82980C-2E2F-5A58-A68F-83CBE1818553","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell One Arm French Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your elbow bent at a 90-degree angle.","Extend your arm straight up towards the ceiling, keeping your elbow stationary.","Slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F54B1DB0-AFC5-58B0-96E5-3336E92ACFAE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('393A86F1-1D25-5CC8-99E6-58667743D449'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"393A86F1-1D25-5CC8-99E6-58667743D449","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Hammer Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad.","Hold the dumbbell with a neutral grip (palms facing your body).","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"75A0057D-8B66-5007-8231-C9A8362CA054","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E484040C-CCC3-57AF-BD77-529B5E52491A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"E484040C-CCC3-57AF-BD77-529B5E52491A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Chest"],"name":"Dumbbell One Arm Hammer Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing inwards and your elbow bent at a 90-degree angle.","Place your other hand on your hip for stability.","Press the dumbbell upwards, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"453ABDFA-1684-57AC-85D1-C90340FAE7D8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EDEA31A4-DD66-542E-AE18-DCB2BB66C626'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"EDEA31A4-DD66-542E-AE18-DCB2BB66C626","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell One Arm Incline Chest Press","notes":"","plannedSets":3,"proTips":["Adjust the incline bench to a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a dumbbell in one hand with an overhand grip, resting it on your shoulder.","Push the dumbbell up and away from your body, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"18361760-8A8D-5F00-9A23-D475608A8FED","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2083DB3A-2D5A-5BD8-89C3-209F520CFADB'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2083DB3A-2D5A-5BD8-89C3-209F520CFADB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell One Arm Kickback","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in your right hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your right elbow up to your side, keeping it bent at a 90-degree angle.","Extend your right arm straight back, squeezing your triceps at the top of the movement.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"43CAFF7D-25F4-5E05-870F-D92E04109E79","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CC85CEDB-CAE2-5B72-98ED-76EF56A829AC'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"CC85CEDB-CAE2-5B72-98ED-76EF56A829AC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Triceps"],"name":"Dumbbell One Arm Lateral Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.","Keep your back straight and your core engaged throughout the exercise.","Raise the dumbbell to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A1C2D563-9A6A-5EB9-A5E4-6486E3210136","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('591AA1A5-0377-59E5-B94B-6448DBBEB001'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"591AA1A5-0377-59E5-B94B-6448DBBEB001","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rotator Cuff"],"name":"Dumbbell One Arm Lateral Raise With Support","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your palm facing your body.","Place your other hand on a stable surface, such as a bench or wall, for support.","Keep your back straight and engage your core.","Raise the dumbbell out to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"01FA9464-7751-5D93-BDA8-01902D93099A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('09370C2B-56D7-584B-AECC-7F8AF416A193'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"09370C2B-56D7-584B-AECC-7F8AF416A193","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps","Core"],"name":"Dumbbell One Arm Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in one hand and position it at shoulder height, with your elbow bent and palm facing forward.","Slowly press the dumbbell upward until your arm is fully extended, while keeping your core engaged and maintaining balance on the exercise ball.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"01943F6F-B8B8-5014-BC13-6E7E794AA24C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DF54AADC-A22A-5034-92AE-853C24D38604'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"DF54AADC-A22A-5034-92AE-853C24D38604","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Prone Curl","notes":"","plannedSets":3,"proTips":["Lie face down on a flat bench with a dumbbell in one hand, palm facing down.","Extend your arm fully, letting it hang straight down towards the floor.","Keeping your upper arm stationary, curl the dumbbell up towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D912FE92-CE1B-5556-AD06-779EC64DED64","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D3F10CAC-48B3-5E8F-9DC9-B018C2457066'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"D3F10CAC-48B3-5E8F-9DC9-B018C2457066","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Prone Hammer Curl","notes":"","plannedSets":3,"proTips":["Lie face down on a flat bench with a dumbbell in one hand, palm facing your body and arm fully extended.","Keep your upper arm stationary and curl the dumbbell towards your shoulder, contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"38750963-FBE7-533D-9CA4-002145E0BD96","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E0B13795-9BD0-5106-9998-A763AB38A00D'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"E0B13795-9BD0-5106-9998-A763AB38A00D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Latissimus Dorsi","Rhomboids"],"name":"Dumbbell One Arm Pullover On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell with one hand and extend your arm straight up above your chest.","Slowly lower the dumbbell behind your head while keeping your arm straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CF1A0116-5217-5EED-8E69-181447D431E7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('142D2C65-1414-55E4-BEE5-2E8E3DBE920E'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"142D2C65-1414-55E4-BEE5-2E8E3DBE920E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell One Arm Reverse Fly (With Support)","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing inwards.","Lean forward and place your free hand on the bench for support.","Keep your arm slightly bent and raise it out to the side until it is parallel to the ground.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CE097843-243F-535B-9206-9833F2681661","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('567581DF-D6BA-51B2-9F9E-A912BF2C65E4'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"567581DF-D6BA-51B2-9F9E-A912BF2C65E4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell One Arm Reverse Grip Press","notes":"","plannedSets":3,"proTips":["Sit on a flat bench with a dumbbell in one hand, palm facing towards your body.","Place your feet flat on the ground and keep your back straight.","Raise the dumbbell to shoulder height, keeping your elbow close to your body.","Press the dumbbell upwards until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"280BE809-7FB2-589C-9854-B05EBDE5D0B9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0CA9CA1A-7CBA-58B1-9824-406AA6CA2C71'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"0CA9CA1A-7CBA-58B1-9824-406AA6CA2C71","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Reverse Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with your chest against the pad and your arm extended over the edge of the bench, holding a dumbbell with an underhand grip.","Lower the dumbbell slowly until your arm is fully extended.","Curl the dumbbell back up towards your shoulder, keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A18E6B68-6F99-5148-A3F0-E1A4D3DF5DB6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('96ACB215-175F-52C1-9A84-EF45F83332E1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"96ACB215-175F-52C1-9A84-EF45F83332E1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Reverse Spider Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in one hand, palm facing down and arm fully extended.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by flexing your elbow.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7D2FD74B-558C-5A43-94A5-F4F326D3EE5B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D9739F2F-1877-5D5D-ABF0-A51C108E0038'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"D9739F2F-1877-5D5D-ABF0-A51C108E0038","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Wrist Extensors"],"name":"Dumbbell One Arm Reverse Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in one hand with an overhand grip, palm facing down.","Rest your forearm on your thigh, with your wrist hanging off the edge.","Slowly lower the dumbbell towards the ground by flexing your wrist.","Pause for a moment at the bottom, then slowly curl your wrist back up towards your body.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2FA62527-4D64-5C65-ABE4-2585A7769C37","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('49EEAD95-97D5-56FD-8437-817294C405AE'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"49EEAD95-97D5-56FD-8437-817294C405AE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Seated Bicep Curl On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your arm fully extended.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DDBC8A2E-DDF6-5F0B-848F-516A96988ED9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F118C2BE-DDDD-5ECE-B049-255155E69A9E'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F118C2BE-DDDD-5ECE-B049-255155E69A9E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Seated Hammer Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in one hand with a neutral grip (palms facing each other).","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E50EA9BE-7E97-5054-92F8-2F803A2DCEC8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('34447C5A-756A-54D0-A069-D09495879CF5'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"34447C5A-756A-54D0-A069-D09495879CF5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Dumbbell One Arm Seated Neutral Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up.","Rest your forearm on your thigh, allowing your wrist to hang off the edge.","Keeping your forearm stationary, curl your wrist upward as far as possible.","Pause for a moment at the top, then slowly lower your wrist back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other hand."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B0188986-070B-5425-B3F3-029692C2B2F8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9A1D3DD3-D3F6-59E4-AADD-6FD1D791DC19'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9A1D3DD3-D3F6-59E4-AADD-6FD1D791DC19","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Dumbbell One Arm Shoulder Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward.","Press the dumbbell upward until your arm is fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"119DB8AC-B44E-5D16-A0B2-FB9ED95A4430","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9B7AF412-8984-59B0-ABA5-6EAAB2217E4F'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9B7AF412-8984-59B0-ABA5-6EAAB2217E4F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Dumbbell One Arm Shoulder Press V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward.","Engage your core and press the dumbbell straight up overhead, fully extending your arm.","Pause for a moment at the top, then slowly lower the dumbbell back to shoulder level.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3567DC42-24FF-5C53-9FF5-FFB51F4992DC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B7CD2C40-5F27-56E5-BAC5-1B10446BCC6B'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B7CD2C40-5F27-56E5-BAC5-1B10446BCC6B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Core"],"name":"Dumbbell One Arm Snatch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Lower the dumbbell towards the ground, keeping it close to your body.","Explosively extend your hips, knees, and ankles, driving the dumbbell upwards in a straight line.","As the dumbbell reaches shoulder height, quickly rotate your hand and punch it overhead, fully extending your arm.","Catch the dumbbell overhead with a slight bend in your knees and hips.","Lower the dumbbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A6652122-5F66-57C0-AE21-726228C20F24","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C2374768-7FB3-595D-A46F-9265781690DB'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"C2374768-7FB3-595D-A46F-9265781690DB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Standing Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in one hand, palm facing forward and arm fully extended.","Keeping your upper arm stationary, exhale and curl the weight upward while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CB6FF6EA-1535-51E0-B12C-92E60AF3CC08","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('04D9DA1E-7138-5F23-B57E-1B85F655BDA2'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"04D9DA1E-7138-5F23-B57E-1B85F655BDA2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Standing Hammer Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"53A4809C-4E7A-59F2-A276-2DB3096E7463","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8ACBA221-3148-51F1-A0D6-6B36E4889216'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"8ACBA221-3148-51F1-A0D6-6B36E4889216","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell One Arm Triceps Extension (On Bench)","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in one hand and place your other hand on the bench for support.","Raise the dumbbell overhead, keeping your upper arm close to your head and your elbow pointing forward.","Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.","Extend your arm back up to the starting position, fully straightening your elbow.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"86F4E7C9-448F-5157-A40B-17D92B70E2EC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B2165A3D-39A6-52AD-903B-0357F73167A1'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B2165A3D-39A6-52AD-903B-0357F73167A1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Dumbbell One Arm Upright Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.","Let the dumbbell hang at arm''s length in front of your thighs, with your palm facing your body.","Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B2B71A31-3D81-5AE5-93BB-8B67A2266057","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EAB7E58F-19EF-5EA3-AA85-083937AFA438'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"EAB7E58F-19EF-5EA3-AA85-083937AFA438","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Dumbbell One Arm Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh.","Allow your wrist to extend, letting the dumbbell roll down towards your fingers.","Slowly curl your wrist back up, bringing the dumbbell towards your forearm.","Repeat for the desired number of repetitions, then switch to the other hand."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DE76A8A9-D2BF-50C4-8283-5734837AEB41","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9A637456-93B1-58AB-BF41-495DF2084195'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9A637456-93B1-58AB-BF41-495DF2084195","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell One Arm Zottman Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher curl bench and hold a dumbbell in one hand with an underhand grip.","Rest your upper arm on the preacher bench pad, allowing your arm to fully extend.","Curl the dumbbell up towards your shoulder, keeping your upper arm stationary.","At the top of the curl, rotate your wrist so that your palm faces up.","Slowly lower the dumbbell back down to the starting position, rotating your wrist back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"07CB32C1-F9A6-5043-88D4-9EAB9FC25B78","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0C7F66D1-C028-5A28-82F4-1F9B714D0BC3'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"0C7F66D1-C028-5A28-82F4-1F9B714D0BC3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell One Leg Fly On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with a dumbbell in each hand, palms facing each other.","Place one foot on the ground and extend the other leg straight out in front of you.","Lean forward slightly and bring your arms out to the sides, keeping a slight bend in your elbows.","Slowly lower the dumbbells down and out to the sides, feeling a stretch in your chest.","Pause for a moment at the bottom, then squeeze your chest muscles to bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F12952CB-536B-5B68-9009-1A073D7D75C7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6DFD0420-AECD-542B-8504-1C11D6302DA1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6DFD0420-AECD-542B-8504-1C11D6302DA1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Over Bench Neutral Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Keeping your upper arms stationary, exhale and curl the dumbbells up towards your shoulders.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9FECCBAA-B158-5291-8A23-4842ED6C2BBA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3D8CC008-D569-55DF-AF62-7DCC30DA7C6F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3D8CC008-D569-55DF-AF62-7DCC30DA7C6F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Over Bench One Arm Neutral Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in one hand and your arm extended over the bench, palm facing up.","Keep your upper arm stationary and curl the dumbbell towards your shoulder, keeping your wrist in a neutral position.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8B542356-2691-5783-B85F-42BEB6F7D19E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('33ED3A31-22FA-5764-8D9A-30705E3B9F3C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"33ED3A31-22FA-5764-8D9A-30705E3B9F3C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Dumbbell Over Bench One Arm Reverse Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down.","Rest your forearm on the bench with your wrist hanging off the edge.","Slowly curl your wrist upwards, bringing the dumbbell towards your forearm.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A9449F0E-C340-5364-8014-A52889340281","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('80E79F25-A70B-50F0-B9C8-3D4F1E54E4DD'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"80E79F25-A70B-50F0-B9C8-3D4F1E54E4DD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Shoulders"],"name":"Dumbbell Over Bench One Arm Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down.","Rest your forearm on the bench with your wrist hanging off the edge.","Slowly curl your wrist upwards, bringing the dumbbell towards your forearm.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A09D416B-EE34-5B45-A732-95813D4C750B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C7822CA1-B522-535C-8398-171638B7A906'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"C7822CA1-B522-535C-8398-171638B7A906","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Dumbbell Over Bench Revers Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the dumbbells towards your body.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1577062F-0DC5-56E3-BD26-004F1E774C2D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('813A5CE6-275B-53C6-AAE4-F5BC678AA6D8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"813A5CE6-275B-53C6-AAE4-F5BC678AA6D8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Dumbbell Over Bench Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your forearms resting on the bench and your palms facing up, holding a dumbbell in each hand.","Allow your wrists to hang over the edge of the bench.","Slowly curl your wrists upward, squeezing your forearms at the top of the movement.","Pause for a moment, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F29DE28F-B91A-5367-88D4-B4E8972A83D3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8BFAC0BF-1524-530A-9160-8B79D8803210'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"8BFAC0BF-1524-530A-9160-8B79D8803210","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Dumbbell Palm Rotational Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Bend forward at the hips, keeping your back straight and your knees slightly bent.","Let your arms hang straight down, palms facing your body.","Engage your core and pull the dumbbells up towards your chest, keeping your elbows close to your body.","As you pull the dumbbells up, rotate your palms so they face away from your body.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower the dumbbells back down to the starting position, rotating your palms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"C2AD15A1-FBCA-5331-BAC7-CD378B71337E","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('8613676D-1D26-5870-A8B3-5965A1F1540E'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"8613676D-1D26-5870-A8B3-5965A1F1540E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Dumbbell Palms In Incline Bench Press","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the backrest and feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing inwards.","Extend your arms straight up above your chest, keeping a slight bend in your elbows.","Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body.","Pause for a moment at the bottom, then press the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DA1069DF-736E-5D6D-AABB-C182EF04C668","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D102D344-D77E-5165-A180-566A116A8FB1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"D102D344-D77E-5165-A180-566A116A8FB1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Peacher Hammer Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D72AF003-715C-5BE8-8D45-DBDC2E7CC1F9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9BB09FA4-2AD3-5EC1-916F-2A7694CEEA7D'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"9BB09FA4-2AD3-5EC1-916F-2A7694CEEA7D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Dumbbell Plyo Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Lower your body into a squat position by bending your knees and pushing your hips back.","As you reach the bottom of the squat, explode upward, jumping off the ground.","While in the air, quickly switch the position of your feet, landing with your opposite foot forward.","Immediately lower your body back into a squat position and repeat the jump, switching your feet again.","Continue alternating the position of your feet with each jump for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9D52888D-4E7F-50C0-8F7B-87100F337E1B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4A4CE80D-ECEE-57D2-B95C-9B4AAA105B3B'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"4A4CE80D-ECEE-57D2-B95C-9B4AAA105B3B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher curl bench with your upper arms resting on the pad and your chest against it.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6AE23CE2-2E0B-52A3-B6A3-666EAB13A4DC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('95CD8B3A-4514-501A-A3E3-0273397386C9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"95CD8B3A-4514-501A-A3E3-0273397386C9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Preacher Curl Over Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with an underhand grip, resting your elbow on the exercise ball.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8422D1BF-E4B2-51CA-9CC9-C74E6EAF54E9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C66BA2B1-0FB4-53B1-A870-B3291082F635'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"C66BA2B1-0FB4-53B1-A870-B3291082F635","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dumbbell Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and dumbbells in each hand, resting on your thighs.","Slowly walk your feet forward, rolling the exercise ball until your lower back is supported on the ball and your knees are at a 90-degree angle.","Raise the dumbbells to shoulder height, palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9EFD8283-E073-5499-9415-E0E36875BED3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3E875710-9BAD-5EF1-859D-AA1C0BEFA1A9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3E875710-9BAD-5EF1-859D-AA1C0BEFA1A9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Dumbbell Pronate-Grip Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your back straight and feet flat on the ground.","Hold a dumbbell with both hands, palms facing down, and extend your arms straight up overhead.","Keeping your upper arms close to your head and elbows pointing forward, slowly lower the dumbbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5CF36B0A-87B5-5792-BDBD-77D0AF9D29F8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F6115603-22CC-5E9F-A918-48DAF7370EE1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F6115603-22CC-5E9F-A918-48DAF7370EE1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Prone Incline Curl","notes":"","plannedSets":3,"proTips":["Adjust the bench to a 45-degree incline.","Lie face down on the bench with your chest and stomach resting against it.","Hold a dumbbell in each hand with your palms facing down and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"11F8DBCD-6BC6-575B-B93A-DCBF4EFA5251","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('98C778A8-5862-55D3-A866-4493A95E4CD2'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"98C778A8-5862-55D3-A866-4493A95E4CD2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Prone Incline Hammer Curl","notes":"","plannedSets":3,"proTips":["Adjust the bench to a 45-degree incline.","Lie face down on the bench with a dumbbell in each hand, palms facing each other.","Allow your arms to hang straight down towards the floor, keeping your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"586466B2-7D6E-5EBD-B552-60985A491504","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B41AB539-44B6-558A-AB66-DE7EAABA6222'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B41AB539-44B6-558A-AB66-DE7EAABA6222","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Latissimus Dorsi","Triceps"],"name":"Dumbbell Pullover","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping a slight bend in your elbows, slowly lower the dumbbell behind your head until you feel a stretch in your chest and shoulders.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A9983879-87ED-50B7-8099-E4DA957B13C7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('29AE90D4-0330-5C50-A10E-5EB1C0AA7DDE'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"29AE90D4-0330-5C50-A10E-5EB1C0AA7DDE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Dumbbell Pullover Hip Extension On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and the dumbbell resting on your thighs.","Slowly walk your feet forward, rolling the exercise ball down your back until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with both hands and extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower the dumbbell behind your head, keeping your arms straight and maintaining control.","Pause for a moment, then raise the dumbbell back to the starting position.","While keeping your arms extended, lift your hips off the ground, squeezing your glutes and engaging your core.","Lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AE40B674-8E3E-57A0-B6D6-BD8AD94945B0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2A646DCA-DAAE-561D-A57A-724572E9D74F'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2A646DCA-DAAE-561D-A57A-724572E9D74F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Latissimus Dorsi"],"name":"Dumbbell Pullover On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball and hold a dumbbell with both hands above your chest, arms extended.","Slowly lower the dumbbell behind your head while keeping your arms straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"81E5E10B-5A23-5C6F-99F4-5B5DDCCC18F9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('26902629-3033-5D9C-83D0-42C3CE7B07BD'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"26902629-3033-5D9C-83D0-42C3CE7B07BD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Dumbbell Push Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level.","Bend your knees slightly and dip your body down, then explosively extend your legs and press the dumbbells overhead.","Lock out your arms at the top of the movement, then lower the dumbbells back to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DCC9279C-E061-587E-B3CA-69C51925CC8B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6F84D3AB-D74F-517E-A692-F557D957733C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6F84D3AB-D74F-517E-A692-F557D957733C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Dumbbell Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"201B0EC4-0792-5595-A3A6-08674F683C89","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D93EE85F-F89B-5887-938F-A168456CEEC3'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"D93EE85F-F89B-5887-938F-A168456CEEC3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Rear Delt Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"99C334EA-BB34-5AB3-A03E-63549458FE08","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('50375630-5A00-57BA-A53F-FB63347E6AA0'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"50375630-5A00-57BA-A53F-FB63347E6AA0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Rear Delt Row_shoulder","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a dumbbell in each hand with your palms facing your body.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arms straight down towards the floor, with a slight bend in your elbows.","Raise the dumbbells out to the sides, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D7D7FD9C-42B7-5DD0-B060-39DBD19C0723","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A68338B2-6017-5269-8DD6-A0386C4877CB'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"A68338B2-6017-5269-8DD6-A0386C4877CB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Rear Fly","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight down towards the ground, palms facing each other.","Keeping a slight bend in your elbows, lift your arms out to the sides and squeeze your shoulder blades together.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D2A6F35D-7330-51C1-A856-B8165FF7BAE8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BE9B79E2-8520-5DA1-81CC-42AFF1D31919'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BE9B79E2-8520-5DA1-81CC-42AFF1D31919","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Dumbbell Rear Lateral Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and core engaged.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D0DDC175-520A-5268-A017-0BE9999BC911","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EDC47B8E-D0BE-5441-B145-6AF20F4F68CF'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"EDC47B8E-D0BE-5441-B145-6AF20F4F68CF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Dumbbell Rear Lateral Raise (Support Head)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3B04F415-13D1-5904-8825-132A9F6EAD08","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9E3C2854-B2D7-5386-843D-D5E9959734D8'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9E3C2854-B2D7-5386-843D-D5E9959734D8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Dumbbell Rear Lunge","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step backward with your right foot, lowering your body into a lunge position.","Bend your left knee and lower your body until your left thigh is parallel to the ground.","Pause for a moment, then push through your left heel to return to the starting position.","Repeat on the other side, stepping back with your left foot."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"696ECE32-6595-59FD-8CCB-647398B68E27","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3FDD2315-C7A6-544D-B4E2-129F6C7D1B53'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3FDD2315-C7A6-544D-B4E2-129F6C7D1B53","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Revers Grip Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AF42C77A-AD07-5B80-97CE-FCC05E71F511","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2074E6D6-D7CF-56E5-AE1A-DDEF24F0A869'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2074E6D6-D7CF-56E5-AE1A-DDEF24F0A869","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell Reverse Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your knees bent.","Hold a dumbbell in each hand with an overhand grip, palms facing towards your feet.","Extend your arms straight up towards the ceiling, keeping a slight bend in your elbows.","Slowly lower the dumbbells towards your chest, allowing your elbows to flare out to the sides.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"850368C4-21DA-5F62-B157-89CC9A8024D3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A7CC1991-6C68-5A93-8CAA-FB40695F4198'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"A7CC1991-6C68-5A93-8CAA-FB40695F4198","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Reverse Fly","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight down in front of you, palms facing each other.","Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"56C6F953-F711-533A-8F7C-B44222215DD4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6F4EB3FB-49D9-58C5-AF36-194F5D5F4E6D'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6F4EB3FB-49D9-58C5-AF36-194F5D5F4E6D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Dumbbell Reverse Grip Incline Bench One Arm Row","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Place a dumbbell on the floor next to the bench.","Stand facing the bench with your feet shoulder-width apart.","Bend at the waist and place your left knee and left hand on the bench for support.","Pick up the dumbbell with your right hand using a reverse grip (palm facing down).","Keep your back straight and your core engaged.","Pull the dumbbell up towards your chest, keeping your elbow close to your body.","Squeeze your back muscles at the top of the movement.","Lower the dumbbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with your left arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"99BDDA9B-AF32-55ED-B321-2C48495678A0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1F06F1B8-E922-5765-97E2-D6223997D118'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1F06F1B8-E922-5765-97E2-D6223997D118","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Dumbbell Reverse Grip Incline Bench Two Arm Row","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your chest against the backrest and your feet flat on the ground.","Hold a dumbbell in each hand with an underhand grip.","Lean forward and let your arms hang straight down, fully extended.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1A223B46-C623-51D7-B121-EBB61C4310B9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('724B485B-C83F-5273-ADBB-2B590EDC1FC4'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"724B485B-C83F-5273-ADBB-2B590EDC1FC4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Dumbbell Reverse Grip Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a dumbbell in each hand with an overhand grip, palms facing your body.","Bend forward at the waist, keeping your back straight and your core engaged.","Let your arms hang straight down, fully extended, with a slight bend in your elbows.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"54A05850-C4EB-5D93-B3FA-2A439BC1C96B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('94BD413E-04E4-546D-832A-6356B4D2A0B4'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"94BD413E-04E4-546D-832A-6356B4D2A0B4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Reverse Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.","Hold a dumbbell in each hand with an underhand grip, palms facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells as you contract your biceps.","Continue to curl the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DEC1C262-CE18-5289-BA3F-E35EF87E025B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F80A7340-22AA-5E35-B439-B923A7DC4D94'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F80A7340-22AA-5E35-B439-B923A7DC4D94","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Reverse Spider Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"112B5167-158E-5A50-BE0E-E726E7B9F03B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F0FFBEB3-8B5F-539C-A696-57B6932D75CB'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F0FFBEB3-8B5F-539C-A696-57B6932D75CB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Dumbbell Reverse Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing down.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the dumbbells towards your body.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C05301BB-CA05-5655-A4EB-DDE2D6F74B75","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0CD0E497-0589-5514-BCE3-7131A0595B47'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"0CD0E497-0589-5514-BCE3-7131A0595B47","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Dumbbell Romanian Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your knees to bend slightly.","Lower the dumbbells until you feel a stretch in your hamstrings, then push through your heels and engage your glutes to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1E2A3121-7B3B-5DD5-89C9-DC5257F6BF02","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9DBDF574-C99F-59AC-9995-8D7E51DC99BA'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9DBDF574-C99F-59AC-9995-8D7E51DC99BA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Rotation Reverse Fly","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing inwards.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Rotate your arms so that your palms are facing downwards.","Slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"C0028E9A-B525-5D6B-96A1-DF334B538431","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('72331709-58C2-58B7-9157-3A681B560192'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"72331709-58C2-58B7-9157-3A681B560192","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"Dumbbell Scott Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FF35CCD3-6CBA-50CF-BE75-02003B39E01F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('40CF25C8-CCF7-5B18-AC3C-76EFEB6B83F8'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"40CF25C8-CCF7-5B18-AC3C-76EFEB6B83F8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Biceps"],"name":"Dumbbell Seated Alternate Front Raise","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing your body and arms extended down by your sides.","Keeping your arms straight, raise one dumbbell in front of you until it is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A0A4A897-6ECB-597D-9A5E-64EB08F37292","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('09CFB5A7-65FC-588F-A59E-2CB03F5B2545'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"09CFB5A7-65FC-588F-A59E-2CB03F5B2545","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Seated Alternate Hammer Curl On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.","Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while keeping your palm facing your body.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"62D21F38-4CA0-53E2-B301-F22DC1E3066C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('15B31C17-6063-5C54-BB6D-18AEFF26F754'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"15B31C17-6063-5C54-BB6D-18AEFF26F754","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"Dumbbell Seated Alternate Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward.","Press one dumbbell up overhead, fully extending your arm.","Lower the dumbbell back down to shoulder height.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"02C7DA3D-94C2-5142-8542-28C41AA38A8E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9A14B6BF-F10F-50BD-97E2-B169E6E81833'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9A14B6BF-F10F-50BD-97E2-B169E6E81833","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Dumbbell Seated Alternate Shoulder","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand, palms facing inwards, and raise them to shoulder height.","Press one dumbbell up overhead while keeping the other dumbbell at shoulder height.","Lower the raised dumbbell back to shoulder height while simultaneously pressing the other dumbbell up overhead.","Continue alternating between arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6BFD18FF-0945-5750-8C25-19732E5879AE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('72E7BE7D-E7A4-53ED-851B-1892B1765CB3'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"72E7BE7D-E7A4-53ED-851B-1892B1765CB3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Seated Bench Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with both hands and extend your arms straight up above your head.","Slowly lower the dumbbell behind your head, keeping your elbows close to your ears.","Pause for a moment, then raise the dumbbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F14C1DA3-9AF8-5792-9B66-B5269F3D7A96","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1958C092-555D-546B-9186-AD9EF7AADA27'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1958C092-555D-546B-9186-AD9EF7AADA27","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Seated Bent Arm Lateral Raise","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing your body and your arms bent at a 90-degree angle.","Keeping your elbows bent, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0264EBAA-F910-51C1-8C4E-C6EACAADB9F1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('02F7392F-B5B3-5619-AE2B-7F7FEAB63A9D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"02F7392F-B5B3-5619-AE2B-7F7FEAB63A9D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Back"],"name":"Dumbbell Seated Bent Over Alternate Kickback","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in each hand, palms facing inwards.","Bend forward at the waist, keeping your back straight and parallel to the ground.","Extend one arm straight back, keeping it close to your body, until your arm is fully extended.","Pause for a moment, then slowly lower the dumbbell back to the starting position.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2D308FC9-7365-54A7-9998-B1F63F936002","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F42263D7-3BDD-5B99-A696-3A58CDD168F9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F42263D7-3BDD-5B99-A696-3A58CDD168F9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Back"],"name":"Dumbbell Seated Bent Over Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand.","Bend forward at the waist, keeping your back straight and your head up.","Extend your arms straight back, keeping your elbows close to your head.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"87F67E57-BC9F-5E9B-B41C-0A63B147B78E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6C33B50B-3743-5AEE-BF1F-75A9DEA6C1D8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6C33B50B-3743-5AEE-BF1F-75A9DEA6C1D8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Seated Bicep Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D0E7C46C-ECD4-5A80-95DC-F94B9E741DF7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('49C72A5E-24A4-5CDF-AF7B-D50A7B5D31A5'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"49C72A5E-24A4-5CDF-AF7B-D50A7B5D31A5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Seated Biceps Curl (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FE004E80-0D84-5266-9287-EA46C5BF2D50","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4EB56AEC-DEAF-5C83-A289-6E03A44CD015'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"4EB56AEC-DEAF-5C83-A289-6E03A44CD015","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Shoulders"],"name":"Dumbbell Seated Biceps Curl To Shoulder Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing forward and arms fully extended.","Keeping your elbows close to your sides, curl the dumbbells up towards your shoulders.","Once your forearms are vertical, rotate your wrists so that your palms are facing forward.","Press the dumbbells overhead until your arms are fully extended.","Lower the dumbbells back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5CB2D3B3-76E4-541B-B4B6-F33EDDC62D44","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7D1F06FE-1F98-57B8-A3BA-F4F8ADDB67CD'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7D1F06FE-1F98-57B8-A3BA-F4F8ADDB67CD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Dumbbell Seated Calf Raise","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs.","Place the balls of your feet on a raised surface such as a step or block, with your heels hanging off the edge.","Hold onto the dumbbell for stability.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7647D1BE-DE26-58CB-AD71-DDC7AEB860F6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('67728532-6F6B-5E36-B417-CBB7F6019407'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"67728532-6F6B-5E36-B417-CBB7F6019407","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Seated Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, palms facing forward.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3FEDB130-1ABB-5D30-A00E-EA38CBDF40F0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
