  ('31F79564-5D7E-50FD-87DD-278C9555C12A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"31F79564-5D7E-50FD-87DD-278C9555C12A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Seated Kickback","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand.","Bend your knees slightly and lean forward from your hips, keeping your back straight.","Bring your upper arms close to your sides and keep your elbows bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9D491B22-E5E9-50DD-A69E-9D34BECC020C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('864621CC-7F5C-5BAC-8A6A-5E75C8141319'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"864621CC-7F5C-5BAC-8A6A-5E75C8141319","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Upper Back"],"name":"Dumbbell Seated Lateral Raise","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.","Keep your back straight and core engaged.","Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"54A932C1-DCBF-58B4-8F4B-A6F5595057C0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1E56FE8F-A1A7-57C5-95E8-B1573C9D96C9'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1E56FE8F-A1A7-57C5-95E8-B1573C9D96C9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Triceps"],"name":"Dumbbell Seated Lateral Raise V. 2","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.","Keep your back straight and core engaged.","Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5F592DEB-2950-5B36-BBF1-E8323E7764E7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('004AD38E-E17C-51F2-84D0-B8AEE5B79888'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"004AD38E-E17C-51F2-84D0-B8AEE5B79888","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Seated Neutral Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing each other.","Rest your forearms on your thighs, allowing the dumbbells to hang down.","Keeping your wrists in a neutral position, curl the dumbbells up towards your shoulders.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E88B28C0-8FB2-5C5A-AC27-F04B49DD3BA9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('170724E3-8C18-5CC3-B3DF-57AE29148779'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"170724E3-8C18-5CC3-B3DF-57AE29148779","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Dumbbell Seated One Arm Bicep Curl On Exercise Ball With Leg Raised","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your arm fully extended.","Place your other hand on your hip for stability.","Slowly curl the dumbbell towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top of the movement, squeezing your bicep.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"464AFA53-6C9A-59AE-B65A-FA7C084B8C1B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('50B0F73B-0131-5F7A-9E03-764E605D95D2'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"50B0F73B-0131-5F7A-9E03-764E605D95D2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Seated One Arm Kickback","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand.","Bend your torso forward at the waist, keeping your back straight and parallel to the ground.","Extend your arm straight back, keeping your elbow close to your body.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9A50C550-5684-56FA-91B0-81304E3DF729","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('23C3B1A2-E6B5-5436-9C36-612BF94BE48C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"23C3B1A2-E6B5-5436-9C36-612BF94BE48C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Shoulders","Biceps"],"name":"Dumbbell Seated One Arm Rotate","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and hold a dumbbell in one hand, resting it on your thigh.","Raise the dumbbell up to shoulder height, keeping your elbow close to your body.","Rotate your forearm outward, away from your body, while keeping your upper arm stationary.","Pause for a moment at the top, then slowly rotate your forearm back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2A9B676A-AE22-5C1E-B3A0-7AB9DFACFE6B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AAE7D3F5-C28A-582D-AD9D-073ABE9444D1'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"AAE7D3F5-C28A-582D-AD9D-073ABE9444D1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Dumbbell Seated One Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your right thigh.","Extend your left leg straight out in front of you, keeping your foot flexed.","Place the ball of your right foot on an elevated surface, such as a step or weight plate.","Using your calf muscles, raise your right heel as high as possible.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4B4185E9-FE45-5614-9C1A-F44005D63617","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7F3EE1EB-631A-5E40-8D30-505524C479B5'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7F3EE1EB-631A-5E40-8D30-505524C479B5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Dumbbell Seated One Leg Calf Raise - Hammer Grip","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs.","Place one foot on a raised surface, such as a step or block, with your heel hanging off the edge.","Hold the dumbbell with a hammer grip, meaning your palms are facing each other and your fingers are wrapped around the handle.","Keeping your core engaged and your back straight, slowly raise your heel as high as possible by pushing through the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C468B842-32A9-5567-9E36-BF035997EF9D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E1B90626-6209-5EA9-9891-D5177B68C811'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"E1B90626-6209-5EA9-9891-D5177B68C811","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Dumbbell Seated One Leg Calf Raise - Palm Up","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your back straight and your feet flat on the ground.","Hold a dumbbell in one hand and place it on top of your thigh, palm facing up.","Lift one leg off the ground and extend it in front of you, keeping your knee slightly bent.","Raise your heel as high as possible by pushing through the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A6AC3CA0-AFCA-535F-AAEE-612F0F49FF3B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('622EC381-AE4E-58B1-8DA6-F4FCF51B15EF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"622EC381-AE4E-58B1-8DA6-F4FCF51B15EF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Shoulders"],"name":"Dumbbell Seated Palms Up Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, squeezing your forearms at the top of the movement.","Pause for a moment, then lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2A18CFA0-21DE-5D32-B55B-599067F2C0A7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FBB57F0B-E2AE-576A-884E-26DF5016CF0A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"FBB57F0B-E2AE-576A-884E-26DF5016CF0A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Seated Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher curl bench with your feet flat on the floor.","Hold a dumbbell in one hand with an underhand grip, resting your upper arm against the preacher pad.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0B5DCCE6-60CC-5782-A6F1-1A7924FA59AE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1DC34930-2189-50E6-8225-8465ADB17391'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1DC34930-2189-50E6-8225-8465ADB17391","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Seated Revers Grip Concentration Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up.","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1062F75E-B3DB-52D5-ACA9-09A09E115D5A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('71644037-147F-515E-994F-AF4819B1EDAC'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Dumbbell","hint":"","id":"71644037-147F-515E-994F-AF4819B1EDAC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Seated Reverse Grip One Arm Overhead Tricep Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with an underhand grip and extend your arm straight up overhead.","Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.","Pause for a moment, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D1D7EAEF-EC4A-5638-979C-38F4AEBAC2C5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('85426C36-5444-5A44-A699-543F0894342C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"85426C36-5444-5A44-A699-543F0894342C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Dumbbell Seated Shoulder Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in each hand, resting on your thighs.","Raise the dumbbells to shoulder height, palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1DF88181-4541-5239-AF9B-B7CF20CD2263","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('21CDD140-0029-5D47-AA5D-634F0F2F7EC3'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"21CDD140-0029-5D47-AA5D-634F0F2F7EC3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Dumbbell Seated Shoulder Press (Parallel Grip)","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in each hand, palms facing inward.","Raise the dumbbells to shoulder height, elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"67BE740E-7229-5053-AB43-2916651A19B0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('65DF2A7C-6B8B-5BBC-9360-AA080DACD344'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"65DF2A7C-6B8B-5BBC-9360-AA080DACD344","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Seated Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with both hands and extend your arms straight up overhead.","Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears.","Pause for a moment, then straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"034C2374-74DE-5C64-BDE4-F702924B0348","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1E6B127D-E43D-59EF-9FF9-6B71E9FDD63F'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1E6B127D-E43D-59EF-9FF9-6B71E9FDD63F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders"],"name":"Dumbbell Shrug","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body.","Keep your arms straight and let the dumbbells hang by your sides.","Raise your shoulders as high as possible, as if you are trying to touch your ears with your shoulders.","Hold the contraction for a second, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"096C854C-7B4D-50AB-B1B1-5AA55CEF5A44","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BFBB27CB-8C94-5C0F-9DF1-C86FDE6CC686'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BFBB27CB-8C94-5C0F-9DF1-C86FDE6CC686","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Dumbbell Side Bend","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, letting it hang down by your side.","Keeping your back straight and your core engaged, slowly bend sideways at the waist towards the opposite side of the dumbbell, lowering the weight as far as you comfortably can.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0BF489BB-2D11-5EE6-AB04-9D4498CB1F46","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('42B4144D-BAA1-5D9B-B688-D47B8D151F06'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"42B4144D-BAA1-5D9B-B688-D47B8D151F06","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Dumbbell Side Lying One Hand Raise","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs extended and your head supported by your arm.","Hold a dumbbell in your top hand with your palm facing down.","Keeping your arm straight, raise the dumbbell up to shoulder height.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2C938B49-C46B-53CE-9DCC-5160291CD517","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6C849F53-8976-59E8-9BB7-1D988CC0DF03'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6C849F53-8976-59E8-9BB7-1D988CC0DF03","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Shoulders","Core"],"name":"Dumbbell Side Plank With Rear Fly","notes":"","plannedSets":3,"proTips":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, keeping your elbow bent at a 90-degree angle.","Hold a dumbbell in your top hand, with your arm extended straight down towards the ground.","Engage your core and lift your hips off the ground, creating a straight line from your head to your heels.","While maintaining the side plank position, lift the dumbbell up towards the ceiling, squeezing your shoulder blades together.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CE047154-636A-5405-B1C1-2FBF28F46B3B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A5544A44-1AC3-53CC-B63A-F3DD5E10B17B'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Dumbbell","hint":"","id":"A5544A44-1AC3-53CC-B63A-F3DD5E10B17B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Core"],"name":"Dumbbell Single Arm Overhead Carry","notes":"","plannedSets":3,"proTips":["Stand tall with your feet shoulder-width apart, holding a dumbbell in one hand.","Raise the dumbbell overhead, fully extending your arm.","Engage your core and keep your back straight as you walk forward, maintaining the dumbbell overhead.","Continue walking for the desired distance or time.","Switch hands and repeat the exercise."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"67DB13F1-4CFA-59D9-BCCC-8A80B2D04A3E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3562805A-938B-5EDF-A476-2071D807B7AE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3562805A-938B-5EDF-A476-2071D807B7AE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles"],"name":"Dumbbell Single Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Stand on the edge of a step or platform with your heels hanging off and your toes on the step.","Hold a dumbbell in one hand and place your other hand on a wall or railing for support.","Raise your heel as high as possible, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heel back down below the step.","Repeat for the desired number of repetitions, then switch to the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A2354F1C-4EEE-503D-94CA-F87820DDF868","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8FE80765-59E7-587D-B6FB-F1C24FBF0966'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"8FE80765-59E7-587D-B6FB-F1C24FBF0966","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Dumbbell Single Leg Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart, holding a dumbbell in your right hand.","Shift your weight onto your left leg and lift your right foot slightly off the ground.","Keeping your back straight, hinge forward at the hips and lower the dumbbell towards the ground.","At the same time, extend your right leg straight behind you, maintaining a slight bend in your left knee.","Lower the dumbbell until your torso and right leg are parallel to the ground.","Pause for a moment, then engage your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2A4B4F0E-5FA4-58F9-A1F4-4975EA6597C3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6A801C85-A795-551B-BAF2-A9D6B466D948'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"6A801C85-A795-551B-BAF2-A9D6B466D948","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Dumbbell Single Leg Deadlift With Stepbox Support","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart, holding a dumbbell in your right hand.","Place your left foot on a stepbox or elevated surface behind you.","Keeping your back straight and core engaged, hinge forward at the hips, lowering the dumbbell towards the ground.","As you lower the dumbbell, simultaneously lift your left leg behind you, maintaining a straight line from head to heel.","Lower the dumbbell until you feel a stretch in your right hamstring, then return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"524E7069-223C-5379-9EA8-017F69FBD207","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5041616B-DFDD-5A3F-A485-3EEFB57AEC95'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"5041616B-DFDD-5A3F-A485-3EEFB57AEC95","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Dumbbell Single Leg Split Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with one foot and position your feet so that your front foot is flat on the ground and your back foot is elevated on a bench or step.","Lower your body by bending your front knee and hip, keeping your back knee slightly bent and your back heel off the ground.","Continue lowering until your front thigh is parallel to the ground, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F4F52E49-7978-53DA-A25A-0A2625752132","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EAE37475-5535-564A-A6D5-E05B8D9FE0F1'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"EAE37475-5535-564A-A6D5-E05B8D9FE0F1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Dumbbell Single Leg Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Extend one leg forward and keep it off the ground throughout the exercise.","Bend your standing leg and lower your body down as if sitting back into a chair.","Keep your chest up and your back straight.","Pause for a moment at the bottom, then push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A9AFB1C2-5147-5625-BA65-B623306D06FE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FA2820B7-BB38-5ADF-9033-67430014210A'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"FA2820B7-BB38-5ADF-9033-67430014210A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Dumbbell Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Keeping your chest up and core engaged, lower your body down by bending at the knees and hips, as if sitting back into a chair.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1B26F211-F700-565B-BACB-59261A437504","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0F431B62-C628-5041-9531-60524DC0817A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"0F431B62-C628-5041-9531-60524DC0817A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Dumbbell Standing Alternate Hammer Curl And Press","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your back straight.","Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the curl with your left hand.","After completing the curl with your left hand, exhale and press the dumbbell in your right hand overhead.","Extend your arm fully and hold for a moment at the top.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the press with your left hand.","Continue alternating between curls and presses for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AD0A8936-0C32-565C-8318-9775B579DE98","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('54CFD72C-6B4A-5F9B-8986-D75F4C74957C'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Dumbbell","hint":"","id":"54CFD72C-6B4A-5F9B-8986-D75F4C74957C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Dumbbell Standing Alternate Overhead Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward.","Press one dumbbell overhead, fully extending your arm.","Lower the dumbbell back to shoulder level.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8A749E2F-1AF8-5DD0-911D-DB8C3B222661","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9EE08D77-A81D-5C6E-A979-13DEC7C0C113'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9EE08D77-A81D-5C6E-A979-13DEC7C0C113","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Forearms"],"name":"Dumbbell Standing Alternate Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and your core engaged.","Raise one dumbbell to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6384DAC3-EC5E-59F4-B6F4-C1E55176FF16","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0B8DFF70-B77C-5495-9A0A-731A0519509D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"0B8DFF70-B77C-5495-9A0A-731A0519509D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Standing Alternating Tricep Kickback","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight back, keeping your elbows close to your body.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat with the other arm, alternating sides with each repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"21559A01-5389-5B9C-8D87-17F3966D3650","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DCDBF942-5AE7-514A-800F-15B163CB1CB5'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"DCDBF942-5AE7-514A-800F-15B163CB1CB5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Forearms"],"name":"Dumbbell Standing Around World","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Extend your arms straight out to the sides at shoulder height, palms facing down.","Keeping your arms straight, slowly rotate your arms in a circular motion, bringing the dumbbells in front of your body and then overhead.","Continue the circular motion, bringing the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E737ADF9-7D83-5A30-861A-403750A8F874","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('01835AA2-1268-5AEC-B83A-4070FF2D1768'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"01835AA2-1268-5AEC-B83A-4070FF2D1768","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Back"],"name":"Dumbbell Standing Bent Over One Arm Triceps Extension","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Bend forward at the waist, keeping your back straight and parallel to the ground.","Extend your arm straight back, keeping your elbow close to your body.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4D1DA0CD-D2A7-58F4-B924-72422F0D683F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('97F73A64-EF9C-5B97-8489-CAB2933D5464'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"97F73A64-EF9C-5B97-8489-CAB2933D5464","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Back"],"name":"Dumbbell Standing Bent Over Two Arm Triceps Extension","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Extend your arms straight back, keeping your elbows close to your body.","Slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3E57FB15-F520-53D3-9B39-56DB27E7EB75","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A41DE7C4-5C89-5060-A2E8-DED534AC352F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"A41DE7C4-5C89-5060-A2E8-DED534AC352F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F1B21DEF-98FD-5460-9D23-5618D663284F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('75F7F9F9-E270-53C3-BDE6-BD7DE663D8DD'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"75F7F9F9-E270-53C3-BDE6-BD7DE663D8DD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles"],"name":"Dumbbell Standing Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"42939894-CD50-5E54-BD4D-EC6F77173C2B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5E0B6952-250E-5BC3-B55A-7C57C0AA5690'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"5E0B6952-250E-5BC3-B55A-7C57C0AA5690","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing Concentration Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your arm fully extended and palm facing inwards.","Place your opposite hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7595F150-E0A3-5CD3-96D6-784B94F47C8B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4118145B-8AB9-5CA8-9856-F59902F4FABD'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"4118145B-8AB9-5CA8-9856-F59902F4FABD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Biceps"],"name":"Dumbbell Standing Front Raise Above Head","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keep your arms straight and lift the dumbbells in front of you, raising them above your head.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"22E5BA6B-6581-5D94-8555-DD1CF23887FF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('030589A0-C167-55B0-B5C7-22A5C4F75E27'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"030589A0-C167-55B0-B5C7-22A5C4F75E27","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing Inner Biceps Curl V. 2","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","While holding your upper arms stationary, curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in.","Repeat for the recommended amount of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7F82F70E-A7B0-5A21-A6D6-9452259520F2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7EC09D66-7C64-5345-A43E-9DFC68B2046F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7EC09D66-7C64-5345-A43E-9DFC68B2046F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Standing Kickback","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3DCE8E2C-CE5A-53B3-9635-353DA9E23957","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('56DD0488-3508-5869-AD5E-0C542392734C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"56DD0488-3508-5869-AD5E-0C542392734C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing One Arm Concentration Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, palm facing up.","Place your free hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3D1175EC-FF02-55D0-80BE-93790BAEA2A8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9D00A874-8FD5-5AD1-8CA2-91F84E12E3FC'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9D00A874-8FD5-5AD1-8CA2-91F84E12E3FC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing One Arm Curl (Over Incline Bench)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing forward.","Place your other hand on an incline bench for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"51EF8383-95B3-5906-9012-398983D42F96","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AFFDEB17-761D-56C9-81D5-BE9115B190AA'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"AFFDEB17-761D-56C9-81D5-BE9115B190AA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing One Arm Curl Over Incline Bench","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand.","Place your other hand on an incline bench for support.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1F44BC29-5343-5090-9FD8-C4D8DFC1AE42","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BCB4A656-ACA8-558B-B5EB-225CF674772A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BCB4A656-ACA8-558B-B5EB-225CF674772A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Standing One Arm Extension","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand.","Raise the dumbbell overhead, fully extending your arm.","Keep your upper arm close to your head and perpendicular to the ground.","Slowly lower the dumbbell behind your head, bending your elbow.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"87AB20B2-EC58-5199-85F1-D5DE7E250261","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('25E2ECDD-65D0-55BE-8A77-B98E7B626297'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"25E2ECDD-65D0-55BE-8A77-B98E7B626297","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Dumbbell Standing One Arm Palm In Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand at shoulder height with your palm facing inwards.","Engage your core and keep your back straight.","Press the dumbbell upwards until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D585D7DF-892E-50BB-9842-6A2403A8302F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('59F60446-01CB-56CE-821B-403FAA88812C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"59F60446-01CB-56CE-821B-403FAA88812C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing One Arm Reverse Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand with an overhand grip.","Keep your arm fully extended and close to your body, with your palm facing down.","Slowly curl the dumbbell up towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"468F15AA-526C-5F75-B7D8-0AA51EA29811","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('93B103FF-6C63-53B6-B5DD-679DE32406AB'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Dumbbell","hint":"","id":"93B103FF-6C63-53B6-B5DD-679DE32406AB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Dumbbell Standing Overhead Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back down to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"923BF780-19AD-523C-8771-83CEDCE6CA50","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EB8E69EB-8C54-52E6-8281-512604137E37'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"EB8E69EB-8C54-52E6-8281-512604137E37","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"Dumbbell Standing Palms In Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing inwards.","Keeping your core engaged and your back straight, press the dumbbells upwards until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3CBBFDD0-0220-5C6A-B1A1-77DD9E5FC130","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9BF2A362-3803-5BC4-8E74-2F0DDF933DF6'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9BF2A362-3803-5BC4-8E74-2F0DDF933DF6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing Preacher Curl","notes":"","plannedSets":3,"proTips":["Stand upright with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Rest the back of your upper arms against the preacher bench or an incline bench, with your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F2B527C7-13EF-5BE1-B64D-40AFAC9B2EBF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8381649B-AF85-52CE-9E6A-1E1D4025E389'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"8381649B-AF85-52CE-9E6A-1E1D4025E389","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing Reverse Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E4368466-4255-56BA-8D7A-3ACC4C8FE791","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5CF6A473-3F69-5E2C-9A8F-CC21505E04D8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"5CF6A473-3F69-5E2C-9A8F-CC21505E04D8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Standing Triceps Extension","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Raise the dumbbell overhead, keeping your arm straight.","Bend your elbow and lower the dumbbell behind your head, keeping your upper arm stationary.","Extend your arm back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F13CB540-450F-5E89-9501-FA990FBDB4A5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BF17B715-9131-5F8A-8861-F5E7CDC30B2D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BF17B715-9131-5F8A-8861-F5E7CDC30B2D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Standing Zottman Preacher Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing forward.","Place your upper arms against the preacher bench and keep your elbows slightly bent.","Curl the dumbbells up towards your shoulders while keeping your upper arms stationary.","At the top of the movement, rotate your wrists so that your palms are facing downward.","Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as well.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D1D2EF4A-B4F4-5A28-B9DA-C80830D15535","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('83CF467C-695D-5FB2-A52E-A1E9285291B0'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"83CF467C-695D-5FB2-A52E-A1E9285291B0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Quadriceps","Glutes","Hamstrings"],"name":"Dumbbell Step Up Single Leg Balance With Bicep Curl","notes":"","plannedSets":3,"proTips":["Stand in front of a step or platform with a dumbbell in each hand, palms facing your body.","Place your right foot on the step, ensuring your entire foot is in contact with the surface.","Engage your core and push through your right heel to lift your body up onto the step, bringing your left knee up towards your chest.","At the top of the movement, perform a bicep curl by bending your elbows and bringing the dumbbells towards your shoulders.","Lower the dumbbells back down and simultaneously lower your left foot back to the ground.","Repeat the movement on the opposite side, stepping up with your left foot and curling the dumbbells.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1E3CE30E-C669-5F4C-9830-7D50321C99EC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('451FB07F-6B59-5F26-BB17-0ED731B38564'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"451FB07F-6B59-5F26-BB17-0ED731B38564","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Dumbbell Step-Up","notes":"","plannedSets":3,"proTips":["Stand in front of a bench or step with a dumbbell in each hand, palms facing your body.","Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface.","Push through your right heel and lift your body up onto the bench or step, straightening your right leg.","Bring your left foot up onto the bench or step, standing fully upright.","Step back down with your left foot, followed by your right foot, returning to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8F677EE8-8D6C-59BA-9420-C27D6BFB6076","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B288CEE5-61BF-5539-9C61-765AAF5BD869'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B288CEE5-61BF-5539-9C61-765AAF5BD869","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Dumbbell Step-Up Lunge","notes":"","plannedSets":3,"proTips":["Stand in front of a step or platform with a dumbbell in each hand, palms facing your sides.","Place your right foot on the step, ensuring your entire foot is on the surface.","Push through your right heel and lift your body up onto the step, bringing your left foot up as well.","Once both feet are on the step, lower your left foot back down to the starting position, keeping your right foot on the step.","Repeat the movement, alternating which foot you step up with each time.","Continue for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A6B38D04-01DC-50A9-BB77-F264C0DD036E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('22B9605B-6E77-5175-A442-813D875BB990'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"22B9605B-6E77-5175-A442-813D875BB990","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Dumbbell Step-Up Split Squat","notes":"","plannedSets":3,"proTips":["Stand in front of a bench or step with a dumbbell in each hand, palms facing your body.","Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface.","Step up onto the bench or step with your right foot, pushing through your heel to lift your body up.","As you step up, simultaneously lift your left knee towards your chest.","Pause at the top of the movement, then slowly lower your left foot back to the ground while keeping your right foot on the bench or step.","Repeat the movement with your left foot on the bench or step.","Continue alternating between your right and left foot for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F6141464-4231-5D5B-B674-FFA7BC147EFD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9DBDFD1F-6B01-51D5-9B4B-0054BB8E1F7F'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"9DBDFD1F-6B01-51D5-9B4B-0054BB8E1F7F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Dumbbell Stiff Leg Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing a slight bend in your knees.","Lower the dumbbells until you feel a stretch in your hamstrings, then squeeze your glutes and push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6B25DBC1-7658-5D2D-9E98-F291D5B07CCC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('11F523D1-47C4-5D80-B0A3-B6B085BFD407'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"11F523D1-47C4-5D80-B0A3-B6B085BFD407","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Latissimus Dorsi","Triceps"],"name":"Dumbbell Straight Arm Pullover","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your head at one end and your feet planted firmly on the ground.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping your arms straight, slowly lower the dumbbell behind your head in an arc-like motion.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A3A3C695-9B14-58A4-A826-DE1675B569C6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('17A9AB12-0705-5BE5-87B8-E98CFBF4B2AA'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"17A9AB12-0705-5BE5-87B8-E98CFBF4B2AA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Dumbbell Straight Leg Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your torso to lean forward.","Continue lowering the dumbbells until you feel a stretch in your hamstrings, keeping your knees slightly bent.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3700CF2F-DD3C-5AA0-95FC-ECCE53EC800A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('704E16DF-4237-5491-B74A-04165F6E2BC1'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"704E16DF-4237-5491-B74A-04165F6E2BC1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Core"],"name":"Dumbbell Sumo Pull Through","notes":"","plannedSets":3,"proTips":["Stand with your feet wider than shoulder-width apart, toes pointed outwards.","Hold a dumbbell with both hands in front of your body, arms extended.","Bend your knees and lower your hips down into a squat position, keeping your back straight.","Lower the dumbbell down between your legs, keeping your arms straight.","Drive through your heels and extend your hips forward, pulling the dumbbell up and in front of your body.","Squeeze your glutes at the top of the movement, then lower the dumbbell back down between your legs.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5E66A26E-819C-5AC0-8BA9-246DD350BD2C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D6A34740-D449-5AC8-B6A5-1D3494D9CFD3'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"D6A34740-D449-5AC8-B6A5-1D3494D9CFD3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Dumbbell Supported Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Keeping your chest up and core engaged, slowly lower your body down by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6C130EFD-9E18-5012-8F40-7DF711531B09","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('632DF580-B9F0-5D06-B5E5-78BD61162A07'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"632DF580-B9F0-5D06-B5E5-78BD61162A07","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Tate Press","notes":"","plannedSets":3,"proTips":["Sit on a flat bench with a dumbbell in each hand, palms facing each other.","Raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing away from you.","Press the dumbbells up until your arms are fully extended, then lower them back down to shoulder height.","Rotate your wrists back to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6CCB475A-714A-5F65-8836-3AF5EDC7C345","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BA9FEAED-024D-510C-B34D-E564B1D2AFC6'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"BA9FEAED-024D-510C-B34D-E564B1D2AFC6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbell Tricep Kickback With Stork Stance","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in your right hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your right elbow up to your side, keeping it bent at a 90-degree angle.","Extend your right arm straight back, squeezing your triceps.","Pause for a moment, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C57B6010-6D0C-5FFA-BCA4-6EA9FECB0C35","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3FBBD2A2-1A53-510C-A2C2-301524F199F2'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3FBBD2A2-1A53-510C-A2C2-301524F199F2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Dumbbell Twisting Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand with an overhand grip, palms facing away from you.","Extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower the dumbbells down towards your chest, keeping your elbows close to your body.","As you lower the dumbbells, twist your wrists so that your palms face towards you at the bottom of the movement.","Pause for a moment at the bottom, then reverse the movement by pressing the dumbbells back up to the starting position.","As you press the dumbbells up, twist your wrists back to the starting position with palms facing away from you.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C0A5108D-0441-5E2C-A2D1-AC8E853D4BD0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('378C41BE-E6F2-5109-A587-9BDC4829EE85'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"378C41BE-E6F2-5109-A587-9BDC4829EE85","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Dumbbell Upright Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Let the dumbbells hang in front of your thighs, with your arms fully extended.","Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C31AA804-0BA6-51F6-867B-A314A101562F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3548CDF6-ECAA-5E36-AC5A-D536246576E9'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3548CDF6-ECAA-5E36-AC5A-D536246576E9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Dumbbell Upright Row (Back POV)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Let the dumbbells hang in front of your thighs, with your arms fully extended and your palms facing your body.","Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows.","Continue lifting until the dumbbells are at shoulder height, with your elbows pointing out to the sides.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9DD42C7E-DB69-5D06-8F55-B4C0EE468266","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B381F577-9221-5952-9654-5F98D430BD99'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B381F577-9221-5952-9654-5F98D430BD99","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Rotator Cuff","Trapezius"],"name":"Dumbbell Upright Shoulder External Rotation","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body.","Raise your arms out to the sides until they are parallel to the ground, keeping your elbows slightly bent.","Rotate your arms externally, bringing the dumbbells up towards your head while keeping your elbows in the same position.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"20878EF6-B901-5400-9432-C44D2A6D8D66","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('1293BE1A-3192-596F-8BC2-949B487AC113'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1293BE1A-3192-596F-8BC2-949B487AC113","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"Dumbbell W-Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"37DDB6C2-6E20-5384-85FF-022AD126E056","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9A3C6029-274C-5F3A-BACC-2F188F3E99D8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9A3C6029-274C-5F3A-BACC-2F188F3E99D8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Dumbbell Waiter Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your upper arms close to your body and your elbows tucked in.","Slowly curl the dumbbells up towards your shoulders, keeping your wrists straight.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"23EECE8B-CF34-5958-B862-0EB47B03D8A6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('193DE684-EF4B-5A36-B40B-01721E154995'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"193DE684-EF4B-5A36-B40B-01721E154995","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Zottman Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and rotate your palms to face forward.","Curl the dumbbells up to your shoulders while keeping your upper arms stationary.","At the top of the movement, rotate your wrists so that your palms are facing away from your body.","Slowly lower the dumbbells back to the starting position, rotating your palms back to facing your body.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FC277301-A770-5C80-B065-B5CF4495B896","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2523E1FB-E683-513D-8A07-1EDB73B63A10'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2523E1FB-E683-513D-8A07-1EDB73B63A10","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Zottman Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with a dumbbell in each hand, palms facing up and elbows resting on the pad.","Curl the dumbbells up towards your shoulders, keeping your upper arms stationary and your palms facing up.","At the top of the curl, rotate your wrists so that your palms are facing down.","Slowly lower the dumbbells back down to the starting position, rotating your wrists back to the starting position as you do so.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FA0E8284-F647-5E2A-BAE7-587898CF5174","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('234B4D2B-BE20-5A64-9703-1313B3AB3026'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"234B4D2B-BE20-5A64-9703-1313B3AB3026","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Dumbbells Seated Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in both hands with an overhand grip, and raise it above your head.","Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears.","Extend your arms and raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9615380F-586A-5233-A960-6984048DBC4B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('652BE836-FBEE-5E24-8D62-8F274BC0E177'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"652BE836-FBEE-5E24-8D62-8F274BC0E177","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Dynamic Chest Stretch","notes":"","plannedSets":3,"proTips":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out to the sides, parallel to the ground.","Slowly bring your arms forward, crossing them in front of your body.","Feel the stretch in your chest muscles.","Hold the stretch for 10-30 seconds.","Return to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"07D62B7D-226F-510B-A0D1-5BFE7DB196C7","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('77AA76D9-A0A2-50EF-8CF2-40C0F91267B9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"77AA76D9-A0A2-50EF-8CF2-40C0F91267B9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"EZ Bar French Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball and hold an EZ barbell with an overhand grip.","Extend your arms straight up, keeping your elbows close to your head.","Slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"44C7BF7A-93E9-5ECD-92C6-886468DEC42E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"086B6E52-B8F4-56BA-A7F9-B9B6ADD963B7","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B95ADFBD-9D11-5767-A795-6E091B05EB26","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"A1F072D8-9D68-5208-BF4D-0DB86BC0A4B7","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1D5B6EAE-D609-5ABE-B47B-8AAACE8E119E'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"1D5B6EAE-D609-5ABE-B47B-8AAACE8E119E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Chest"],"name":"EZ Bar Lying Bent Arms Pullover","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold the EZ barbell with a pronated grip (palms facing away from you) and your hands shoulder-width apart.","Extend your arms straight above your chest, keeping a slight bend in your elbows.","Lower the barbell in an arc motion behind your head, maintaining the slight bend in your elbows.","Pause for a moment, then return the barbell to the starting position by reversing the arc motion.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2F731EE7-E839-54A3-B995-9D834D430512","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E9F1EC79-CBD5-5261-BF1B-6E8F75E0521C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"6152FFAC-B336-5A14-B3E4-3C820EB9FB05","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"B11C3B56-5060-519F-BE40-D1BCA729239F","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A38A504A-61AF-553B-A431-2A043AEC226D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"A38A504A-61AF-553B-A431-2A043AEC226D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"EZ Bar Lying Close Grip Triceps Extension Behind Head","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the ez barbell with a close grip, palms facing up, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9BC733F9-D462-52E7-8C65-D53CE49A542A","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0D4C2DEE-6E48-55A6-9E01-E8515BE401F9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"54B1BA4E-58DD-58BB-AE6F-2369BEDB73F1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"CAC14E57-1DCA-5623-BA7C-2AC749B800C1","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F4446F88-13AD-5863-8B70-8F979359861E'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"F4446F88-13AD-5863-8B70-8F979359861E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"EZ Bar Reverse Grip Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the ez barbell with an underhand grip, palms facing up, and hands shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor.","Pull the ez barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the ez barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E09D7B8E-6643-58A8-B39D-9024FDB218B0","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"7550BAFA-58CF-5CC7-8F0E-746B2E6CD17F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B81FB84C-F03A-540C-B581-5FAC06D10B84","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"214F3B7B-26A6-5066-BA08-DC1277108FF1","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4A0DD566-14DF-5312-8F9F-A6E9CCC0A000'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"4A0DD566-14DF-5312-8F9F-A6E9CCC0A000","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"EZ Bar Seated Close Grip Concentration Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold an EZ barbell with an underhand grip.","Rest your elbow on the inside of your thigh, just above the knee.","Curl the barbell up towards your shoulder while keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"CCF0954F-275F-5E38-9B87-4F7064E4CA23","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"B55B8EBB-2136-5C21-A90F-7D977B0665DB","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"32627B8B-832D-5F04-8995-302E3ABA789B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"511D7B31-A526-5A89-850D-0576CE913387","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now())
